import subprocess
from pathlib import Path

APP = Path('/app')

def write_tests():
    path = APP / 'internal/pricing/cache_consistency_recovery_test.go'
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text('\npackage pricing\n\nimport (\n    "context"\n    "sync"\n    "testing"\n    "time"\n\n    "catalog-pricing-service/internal/cache"\n    "catalog-pricing-service/internal/catalog"\n)\n\ntype controlledSource struct {\n    mu      sync.Mutex\n    prices  map[string]catalog.Price\n    calls   map[string]int\n    started chan string\n    release chan struct{}\n}\n\nfunc newControlledSource(prices []catalog.Price) *controlledSource {\n    source := &controlledSource{\n        prices:  make(map[string]catalog.Price),\n        calls:   make(map[string]int),\n        started: make(chan string, 16),\n        release: make(chan struct{}),\n    }\n    for _, price := range prices {\n        source.set(price)\n    }\n    return source\n}\n\nfunc sourceKey(sku, currency string) string { return sku + "\\x00" + currency }\n\nfunc (s *controlledSource) set(price catalog.Price) {\n    s.mu.Lock()\n    s.prices[sourceKey(price.SKU, price.Currency)] = price\n    s.mu.Unlock()\n}\n\nfunc (s *controlledSource) Fetch(ctx context.Context, sku, currency string) (catalog.Price, error) {\n    key := sourceKey(sku, currency)\n    s.mu.Lock()\n    price, ok := s.prices[key]\n    s.calls[key]++\n    s.mu.Unlock()\n    if !ok {\n        return catalog.Price{}, catalog.ErrNotFound\n    }\n    select {\n    case s.started <- key:\n    default:\n    }\n    select {\n    case <-s.release:\n        return price, nil\n    case <-ctx.Done():\n        return catalog.Price{}, ctx.Err()\n    }\n}\n\nfunc (s *controlledSource) callCount(sku, currency string) int {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    return s.calls[sourceKey(sku, currency)]\n}\n\nfunc waitStarted(t *testing.T, ch <-chan string) string {\n    t.Helper()\n    select {\n    case key := <-ch:\n        return key\n    case <-time.After(2 * time.Second):\n        t.Fatal("source fetch did not start")\n        return ""\n    }\n}\n\nfunc TestLateFillCannotRepopulateBelowAcknowledgedVersion(t *testing.T) {\n    source := newControlledSource([]catalog.Price{\n        {SKU: "CAMERA-4K", Currency: "USD", AmountMinor: 129900, Version: 41},\n    })\n    service := NewService(cache.NewStore(time.Minute, nil), source)\n\n    firstDone := make(chan Result, 1)\n    go func() {\n        result, _ := service.GetPrice(context.Background(), "camera-4k", "usd")\n        firstDone <- result\n    }()\n    waitStarted(t, source.started)\n\n    source.set(catalog.Price{SKU: "CAMERA-4K", Currency: "USD", AmountMinor: 119900, Version: 42})\n    service.ApplyInvalidation(Invalidation{SKU: "camera-4k", MinimumVersion: 42})\n    close(source.release)\n\n    if first := <-firstDone; first.Price.Version != 41 {\n        t.Fatalf("in-flight request version = %d, want captured version 41", first.Price.Version)\n    }\n    next, err := service.GetPrice(context.Background(), "CAMERA-4K", "USD")\n    if err != nil {\n        t.Fatalf("next request failed: %v", err)\n    }\n    if next.Price.Version != 42 || next.Price.AmountMinor != 119900 {\n        t.Fatalf("next request returned stale price: %#v", next.Price)\n    }\n    if calls := source.callCount("CAMERA-4K", "USD"); calls != 2 {\n        t.Fatalf("source calls = %d, want 2", calls)\n    }\n}\n\nfunc TestOutOfOrderInvalidationDoesNotLowerVersionFloor(t *testing.T) {\n    source := newControlledSource([]catalog.Price{\n        {SKU: "LENS-50", Currency: "EUR", AmountMinor: 34900, Version: 44},\n    })\n    service := NewService(cache.NewStore(time.Minute, nil), source)\n\n    service.ApplyInvalidation(Invalidation{SKU: "LENS-50", MinimumVersion: 45})\n    service.ApplyInvalidation(Invalidation{SKU: "LENS-50", MinimumVersion: 43})\n\n    firstDone := make(chan Result, 1)\n    go func() {\n        result, _ := service.GetPrice(context.Background(), "LENS-50", "EUR")\n        firstDone <- result\n    }()\n    waitStarted(t, source.started)\n    close(source.release)\n    <-firstDone\n\n    source.release = make(chan struct{})\n    source.set(catalog.Price{SKU: "LENS-50", Currency: "EUR", AmountMinor: 33900, Version: 45})\n    secondDone := make(chan Result, 1)\n    go func() {\n        result, _ := service.GetPrice(context.Background(), "LENS-50", "EUR")\n        secondDone <- result\n    }()\n    waitStarted(t, source.started)\n    close(source.release)\n    second := <-secondDone\n    if second.Price.Version != 45 {\n        t.Fatalf("second request version = %d, want 45", second.Price.Version)\n    }\n    if calls := source.callCount("LENS-50", "EUR"); calls != 2 {\n        t.Fatalf("older invalidation lowered floor; source calls = %d, want 2", calls)\n    }\n}\n', encoding='utf-8')
    path = APP / 'internal/pricing/fill_collapse_recovery_test.go'
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text('\npackage pricing\n\nimport (\n    "context"\n    "sync"\n    "testing"\n    "time"\n\n    "catalog-pricing-service/internal/cache"\n    "catalog-pricing-service/internal/catalog"\n)\n\ntype collapseSource struct {\n    mu      sync.Mutex\n    prices  map[string]catalog.Price\n    calls   map[string]int\n    started chan string\n    release map[string]chan struct{}\n}\n\nfunc newCollapseSource(prices []catalog.Price) *collapseSource {\n    source := &collapseSource{\n        prices:  make(map[string]catalog.Price),\n        calls:   make(map[string]int),\n        started: make(chan string, 128),\n        release: make(map[string]chan struct{}),\n    }\n    for _, price := range prices {\n        key := sourceKey(price.SKU, price.Currency)\n        source.prices[key] = price\n        source.release[key] = make(chan struct{})\n    }\n    return source\n}\n\nfunc (s *collapseSource) Fetch(ctx context.Context, sku, currency string) (catalog.Price, error) {\n    key := sourceKey(sku, currency)\n    s.mu.Lock()\n    price := s.prices[key]\n    release := s.release[key]\n    s.calls[key]++\n    s.mu.Unlock()\n    s.started <- key\n    select {\n    case <-release:\n        return price, nil\n    case <-ctx.Done():\n        return catalog.Price{}, ctx.Err()\n    }\n}\n\nfunc (s *collapseSource) count(key string) int {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    return s.calls[key]\n}\n\nfunc TestConcurrentMissesShareOneSourceFetch(t *testing.T) {\n    price := catalog.Price{SKU: "CAMERA-4K", Currency: "USD", AmountMinor: 119900, Version: 42}\n    source := newCollapseSource([]catalog.Price{price})\n    service := NewService(cache.NewStore(time.Minute, nil), source)\n\n    const callers = 48\n    start := make(chan struct{})\n    results := make(chan Result, callers)\n    errors := make(chan error, callers)\n    var wg sync.WaitGroup\n    for i := 0; i < callers; i++ {\n        wg.Add(1)\n        go func() {\n            defer wg.Done()\n            <-start\n            result, err := service.GetPrice(context.Background(), "camera-4k", "usd")\n            results <- result\n            errors <- err\n        }()\n    }\n    close(start)\n\n    key := waitStarted(t, source.started)\n    if key != sourceKey("CAMERA-4K", "USD") {\n        t.Fatalf("started key = %q", key)\n    }\n    time.Sleep(75 * time.Millisecond)\n    if calls := source.count(key); calls != 1 {\n        t.Fatalf("source calls while fill blocked = %d, want 1", calls)\n    }\n    close(source.release[key])\n    wg.Wait()\n    close(results)\n    close(errors)\n\n    for err := range errors {\n        if err != nil {\n            t.Fatalf("concurrent request failed: %v", err)\n        }\n    }\n    for result := range results {\n        if result.Price.Version != 42 {\n            t.Fatalf("result version = %d, want 42", result.Price.Version)\n        }\n    }\n    if calls := source.count(key); calls != 1 {\n        t.Fatalf("final source calls = %d, want 1", calls)\n    }\n}\n\nfunc TestDifferentPriceKeysFetchIndependently(t *testing.T) {\n    prices := []catalog.Price{\n        {SKU: "CAMERA-4K", Currency: "USD", AmountMinor: 119900, Version: 42},\n        {SKU: "LENS-50", Currency: "USD", AmountMinor: 33900, Version: 45},\n    }\n    source := newCollapseSource(prices)\n    service := NewService(cache.NewStore(time.Minute, nil), source)\n\n    done := make(chan error, 2)\n    go func() { _, err := service.GetPrice(context.Background(), "CAMERA-4K", "USD"); done <- err }()\n    go func() { _, err := service.GetPrice(context.Background(), "LENS-50", "USD"); done <- err }()\n\n    seen := map[string]bool{}\n    deadline := time.After(2 * time.Second)\n    for len(seen) < 2 {\n        select {\n        case key := <-source.started:\n            seen[key] = true\n        case <-deadline:\n            t.Fatalf("different keys were serialized; started=%v", seen)\n        }\n    }\n\n    for key, release := range source.release {\n        close(release)\n        if calls := source.count(key); calls != 1 {\n            t.Fatalf("source calls for %q = %d, want 1", key, calls)\n        }\n    }\n    for i := 0; i < 2; i++ {\n        if err := <-done; err != nil {\n            t.Fatalf("request failed: %v", err)\n        }\n    }\n}\n', encoding='utf-8')

def test_recovery_contracts():
    write_tests()
    result = subprocess.run(
        ['/usr/local/go/bin/go', 'test', '-race', './internal/pricing', '-run', 'Test(LateFill|OutOfOrder|ConcurrentMisses|DifferentPriceKeys)', '-count=1'],
        cwd=APP, text=True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, timeout=120,
    )
    assert result.returncode == 0, result.stdout
